1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const basePremium = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
17	
18	const firstInsuranceSurcharge = (base: number): number =>
19	  Math.ceil((base * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100);
20	
21	const quotePremium = (items: Item[]): number => {
22	  const base = basePremium(items);
23	  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
24	};
25	
26	export const run = (input: unknown): unknown => {
27	  const { steps } = input as Input;
28	  const results = steps.map(({ items }) => ({ premium: quotePremium(items) }));
29	  return { results };
30	};
